# Generated by google (gemini-2.5-flash)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'IMAGE_NAME', defaultValue: 'my-app', description: 'The base name of the Docker image (e.g., my-app)')
        string(name: 'IMAGE_TAG', defaultValue: 'latest', description: 'The tag for the Docker image (e.g., v1.0, latest)')
        string(name: 'REGISTRY_URL', defaultValue: 'docker.io/myusername', description: 'The full URL of the Docker registry including namespace (e.g., docker.io/myusername, private-registry.com/myteam)')
        string(name: 'DOCKER_CREDENTIALS_ID', defaultValue: 'dockerhub-credentials', description: 'Jenkins credentials ID for Docker registry login')
        string(name: 'GIT_REPO_URL', defaultValue: 'https://github.com/jenkinsci/docker-workflow-plugin.git', description: 'The URL of the Git repository containing the Dockerfile')
        string(name: 'GIT_BRANCH', defaultValue: 'master', description: 'The branch of the Git repository to checkout')
    }

    stages {
        stage('Checkout Source Code') {
            steps {
                git branch: GIT_BRANCH, url: GIT_REPO_URL
            }
        }
        stage('Build and Push Docker Image') {
            steps {
                script {
                    def fullImageName = "${REGISTRY_URL}/${IMAGE_NAME}:${IMAGE_TAG}"
                    // Extract the base registry URL for the withDockerRegistry step (e.g., from 'docker.io/myusername' to 'docker.io')
                    def registryBaseUrl = REGISTRY_URL.split('/')[0]

                    // Log in to Docker registry using provided credentials
                    withDockerRegistry(credentialsId: DOCKER_CREDENTIALS_ID, url: "https://${registryBaseUrl}") {
                        // Build the Docker image
                        echo "Building Docker image: ${fullImageName}"
                        sh "docker build -t ${fullImageName} ."

                        // Push the Docker image to the specified registry
                        echo "Pushing Docker image: ${fullImageName}"
                        sh "docker push ${fullImageName}"
                    }
                }
            }
        }
    }
    post {
        always {
            cleanWs() // Clean up workspace after build
        }
    }
}